package arch.day45;

public class Day45Intermediate {
    static boolean flaky(int attempt) { return attempt >= 2; }

    public static void main(String[] args) throws Exception {
        int attempt = 0;
        while (true) {
            attempt++;
            if (flaky(attempt)) {
                System.out.println("ok on " + attempt);
                break;
            }
            Thread.sleep(10);
        }
    }
}

