import java.util.*;
import java.util.concurrent.*;

public class Day45Advanced {
    public static void main(String[] args) throws Exception {
        Semaphore sem = new Semaphore(1, true);
        sem.acquire();
        try {
            System.out.println("critical");
        } finally {
            sem.release();
        }
    }
}

